// ─────────────────────────────────────────────
//  App.js  –  Root component, manages global state
// ─────────────────────────────────────────────
import React, { useState, useEffect, useCallback } from 'react';
import PostForm from './components/PostForm';
import PostList from './components/PostList';
import { fetchPosts } from './api';
import './App.css';

function App() {
  const [posts,   setPosts]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [error,   setError]   = useState('');

  // Fetch all posts from the API
  const loadPosts = useCallback(async () => {
    try {
      setLoading(true);
      setError('');
      const { data } = await fetchPosts();
      setPosts(data);
    } catch (err) {
      setError('Could not connect to the server. Make sure the backend is running.');
    } finally {
      setLoading(false);
    }
  }, []);

  // Load posts once when the app mounts
  useEffect(() => {
    loadPosts();
  }, [loadPosts]);

  return (
    <div className="app">
      {/* ── Header ───────────────────────────── */}
      <header className="site-header">
        <div className="header-inner">
          <div className="logo">
            <span className="logo-mark">✦</span>
            <span className="logo-text">The Blog</span>
          </div>
          <p className="tagline">A simple place to share your thoughts.</p>
        </div>
        <div className="header-line" />
      </header>

      {/* ── Main content ─────────────────────── */}
      <main className="main-content">
        {/* Write form on the left / top */}
        <PostForm onPostCreated={loadPosts} />

        {/* Divider */}
        <div className="divider" />

        {/* Post list on the right / below */}
        <PostList posts={posts} loading={loading} error={error} />
      </main>

      {/* ── Footer ───────────────────────────── */}
      <footer className="site-footer">
        <p>Built with React · Express · MongoDB</p>
      </footer>
    </div>
  );
}

export default App;
